/**
 * PrepareRuleScoringPersistenceNode - Transform rule scoring results to database format
 * Converts RuleScoringNode output to format required by PostgresUpsertRows
 *
 * EXPECTED INPUT (from RuleScoringNode)
 *  Array of emails with rule scoring results:
 *  - gmail_id, session_id, candidate_scores, subtype_scores, rule_matches, etc.
 *
 * OUTPUT FORMAT (for PostgresUpsertRows)
 *  Single item with rows array containing stage_category_eval records:
 *  [{json: {
 *    rows: [{
 *      stage_id: string,
 *      category_code: string,
 *      decision: 'evaluated'|'selected'|'rejected',
 *      score: number,
 *      confidence: string,
 *      scoring_components: jsonb,
 *      rationale: string
 *    }]
 *  }}]
 */

const CodeNode = require('../../../../n8n-simulator/src/nodes/CodeNode');

class PrepareRuleScoringPersistenceNode extends CodeNode {
  constructor() {
    super('PrepareRuleScoringPersistence');
  }

  async execute($input) {
    const inputItems = $input.all();
    console.log('Starting prepare_rule_scoring_persistence node execution');
    console.log(`Processing ${inputItems.length} emails for rule scoring persistence`);

    // Get the stage mapping from workflow static data
    const staticData = $getWorkflowStaticData('global');
    const stageMapping = staticData.stage_mapping;

    if (!stageMapping) {
      console.error('No stage mapping found in workflow static data');
      return [{ json: { rows: [] } }];
    }

    const allRows = [];

    for (const item of inputItems) {
      const email = item.json;
      console.log(`Preparing persistence data for email ${email.gmail_id}`);

      // Get real stage_id from the stage mapping
      const sessionId = email.session_id;
      const stageId = stageMapping[sessionId]?.['rule_scoring'];

      if (!stageId) {
        console.error(`No stage_id found for session ${sessionId}, stage rule_scoring`);
        continue;
      }

      console.log(`Using real stage_id ${stageId} for session ${sessionId}`);

      // Process each category that was scored
      for (const [categoryCode, scoreObject] of Object.entries(email.candidate_scores || {})) {
        // Extract numeric score from score object (RuleScoringNode returns objects)
        const categoryScore = scoreObject.score;
        // Get detailed scoring information for this category
        const subtypeScores = email.subtype_scores?.[categoryCode] || {};
        const ruleMatches = email.rule_matches?.[categoryCode] || [];
        const rationale = email.scoring_rationale?.[categoryCode] || [];

        // Build scoring components object for database storage
        const scoringComponents = {
          subtype_scores: subtypeScores,
          rule_matches: ruleMatches.length,
          rule_match_details: ruleMatches.slice(0, 5), // Limit details to prevent bloat
          scoring_method: 'rule_based',
          bounded_aggregation_applied: Object.keys(subtypeScores).length > 1,
        };

        // Determine decision based on score (using allowed values)
        let decision = 'candidate'; // evaluated -> candidate
        if (categoryScore >= 15) {
          decision = 'positive'; // selected -> positive
        } else if (categoryScore <= 2) {
          decision = 'rejected'; // rejected stays the same
        }

        // Determine confidence level based on score (as numeric)
        let confidence = 0.3; // low
        if (categoryScore >= 12) {
          confidence = 0.8; // high
        } else if (categoryScore >= 6) {
          confidence = 0.6; // medium
        }

        const row = {
          stage_id: stageId,
          category_code: categoryCode,
          decision: decision,
          score: JSON.stringify(scoreObject), // Use the complete score object from RuleScoringNode
          confidence: confidence,
          scoring_components: scoringComponents,
          rationale: rationale.join('; ') || `Rule scoring: ${ruleMatches.length} matches, score ${categoryScore}`,
        };

        allRows.push(row);
        console.log(
          `Prepared row for ${categoryCode}: score=${categoryScore}, decision=${decision}, confidence=${confidence}`
        );
      }
    }

    if (allRows.length === 0) {
      console.log('No scoring data to persist - returning empty rows');
      return [{ json: { rows: [], stage_summaries: [] } }];
    }

    // Prepare stage completion data
    const stageSummaries = [];
    const sessionStages = {};

    for (const item of inputItems) {
      const email = item.json;
      const sessionId = email.session_id;
      const stageId = stageMapping[sessionId]?.['rule_scoring'];

      if (!stageId || sessionStages[stageId]) continue; // Skip duplicates

      // Calculate aggregate weight score for this stage
      const scores = Object.values(email.candidate_scores || {}).map((scoreObj) => scoreObj.score);
      const totalWeight = scores.reduce((sum, score) => sum + score, 0);
      const maxScore = Math.max(...scores);
      const topCategories = Object.entries(email.candidate_scores || {})
        .map(([code, scoreObj]) => [code, scoreObj.score])
        .filter(([_, score]) => score > 0)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 3)
        .map(([cat, score]) => `${cat}:${score}`);

      stageSummaries.push({
        stage_id: stageId,
        weight_score: Math.round(totalWeight * 100) / 100,
        rationale: `Applied rule-based scoring across categories. Top scoring: ${topCategories.join(', ')}. Highest confidence: ${maxScore}. Used keyword matching, domain analysis, and content patterns.`,
        passed_to_next: true,
      });

      sessionStages[stageId] = true;
      console.log(`Prepared stage summary for stage_id ${stageId}: weight_score=${totalWeight}`);
    }

    console.log(
      `Prepared ${allRows.length} rule scoring persistence rows and ${stageSummaries.length} stage summaries`
    );
    return [{ json: { rows: allRows, stage_summaries: stageSummaries } }];
  }
}

module.exports = PrepareRuleScoringPersistenceNode;

