/**
 * PrepareMultiLabelPersistenceNode - Transform multi-label selection results to database persistence format
 *
 * Takes multi-label selection results and formats for storage in:
 * - session_categories table (selected labels for the email)
 *
 * This follows the established n8n pattern: Business Logic → Prepare Persistence → PostgreSQL Node
 */

const CodeNode = require('../../../../n8n-simulator/src/nodes/CodeNode');

class PrepareMultiLabelPersistenceNode extends CodeNode {
  constructor() {
    super('PrepareMultiLabelPersistence');
  }

  execute($input) {
    const inputItems = $input.all();
    console.log('Starting prepare_multi_label_persistence');

    const results = [];
    for (const item of inputItems) {
      const emailData = item.json;

      try {
        console.log(`Preparing multi-label persistence for email ${emailData.gmail_id}`);

        const persistenceData = emailData._persistence_data;
        if (!persistenceData || persistenceData.stage_type !== 'multi_label_selection') {
          console.log(`No multi-label persistence data found for email ${emailData.gmail_id}`);
          results.push({ json: emailData });
          continue;
        }

        const selectedLabels = persistenceData.selected_labels || [];
        const sessionCategories = persistenceData.session_categories || [];

        // Prepare session categories for insertion
        const sessionCategoryRecords = sessionCategories.map((category, index) => ({
          session_id: emailData.session_id,
          category_code: category.category_code || category.category_key,
          subtype_code: category.subtype_code || category.subtype_key || null,
          is_primary: index === 0, // First label is primary
          confidence: category.confidence,
          category_score: category.category_score,
          hard_assertion: category.hard_assertion || false,
          label_order: index + 1,
          scoring_trace: {
            selection_method: category.selection_method || 'threshold_based',
            original_score: category.category_score,
            confidence_level: category.confidence,
            was_ai_enhanced: emailData.needs_ai_classification || false,
            selection_timestamp: new Date().toISOString(),
          },
        }));

        // Create database-ready data
        const dbReadyData = {
          ...emailData, // Preserve original email data

          // Database persistence operations
          _persistence_operations: [
            {
              table: 'session_categories',
              operation: 'insert',
              data: sessionCategoryRecords,
            },
          ],

          // Metadata for downstream processing
          multi_label_selection_completed: true,
          multi_label_selection_timestamp: new Date().toISOString(),
          labels_count: selectedLabels.length,
          primary_label: selectedLabels.length > 0 ? selectedLabels[0].code : null,
          selection_summary: persistenceData.selection_summary,
        };

        console.log(
          `Prepared multi-label persistence for email ${emailData.gmail_id} with ${sessionCategoryRecords.length} labels`
        );
        results.push({ json: dbReadyData });
      } catch (error) {
        console.error(`Error preparing multi-label persistence for email ${emailData.gmail_id}:`, error.message);
        // Include error info but continue processing
        results.push({
          json: {
            ...emailData,
            _persistence_error: error.message,
            multi_label_selection_completed: false,
          },
        });
      }
    }

    // Prepare stage completion data
    const stageSummaries = [];
    const sessionStages = {};

    // Get the stage mapping from workflow static data
    const staticData = $getWorkflowStaticData('global');
    const stageMapping = staticData.stage_mapping;

    if (stageMapping) {
      for (const item of inputItems) {
        const email = item.json;
        const sessionId = email.session_id;
        const stageId = stageMapping[sessionId]?.['multi_label_selection'];

        if (!stageId || sessionStages[stageId]) continue; // Skip duplicates

        // Count selected labels for this stage
        const selectedLabels = email._persistence_data?.selected_labels || [];
        const labelCount = selectedLabels.length;
        const labelNames = selectedLabels.map((label) => label.code).join(', ');

        stageSummaries.push({
          stage_id: stageId,
          weight_score: labelCount, // Number of labels selected as weight score
          rationale: `Selected ${labelCount} final labels: ${labelNames}. Applied confidence thresholds and category co-presence validation for multi-label assignment.`,
          passed_to_next: true,
        });

        sessionStages[stageId] = true;
        console.log(`Prepared stage summary for stage_id ${stageId}: ${labelCount} labels selected`);
      }
    }

    // Add stage summaries to the first result item
    if (results.length > 0) {
      results[0].json.stage_summaries = stageSummaries;
    }

    console.log(
      `Prepared multi-label persistence for ${results.length} emails with ${stageSummaries.length} stage summaries`
    );
    return results;
  }
}

module.exports = PrepareMultiLabelPersistenceNode;

