     2→ * ExplainabilityTrace entity with 9-stage results
     3→ *
     4→ * Detailed audit trail preserving all sophisticated classification reasoning
     5→ * per the scoring logic structure defined in SCORING_LOGIC.md.
     6→ */
     7→
     8→export interface ExplainabilityTrace {
     9→  sessionId: string;
    10→  emailId: string;
    11→
    12→  // Pipeline stage results (preserved from n8n sophistication)
    13→  hardAssertions: HardAssertionResult[];
    14→  strongIndicators: StrongIndicatorResult[];
    15→  ruleScoring: RuleEvaluationResult[];
    16→  attributeDetection: AttributeDetectionResult[];
    17→  attributeInfluence: AttributeInfluenceResult[];
    18→  disambiguation: DisambiguationResult[];
    19→  multiLabelSelection: MultiLabelResult[];
    20→  aiRouting?: AIRoutingResult;
    21→
    22→  // Enhanced for debugging and parallel processing
    23→  stageTimings: Record<string, number>; // Stage execution times in ms
    24→  parallelExecutionMap: Record<string, string[]>; // Which stages ran in parallel
    25→  configurationRefs: Record<string, string>; // Config sections used
    26→
    27→  // Decision audit
    28→  finalDecisionReason: string;
    29→  alternativeCategories: Array<{
    30→    category: string;
    31→    score: number;
    32→    eliminationReason: string;
    33→  }>;
    34→}
    35→
    36→/**
    37→ * Hard Assertions stage results
    38→ * Implements HIGH_CONFIDENCE_FLOOR logic per SCORING_LOGIC.md
    39→ */
    40→export interface HardAssertionResult {
    41→  category: string;
    42→  triggered: boolean;
    43→  assertionType: 'from_domain' | 'subject_prefix' | 'from_address';
    44→  matchedValue: string;
    45→  confidence: 'HIGH_CONFIDENCE' | 'MEDIUM_CONFIDENCE'; // From config
    46→  sourceGroup?: string; // Domain source group if applicable
    47→  reason: string;
    48→}
    49→
