/**
 * Unit Tests for Audit Trail Generation Stage (T036)
 *
 * TDD Approach: These tests are written FIRST and will FAIL until implementation is complete.
 *
 * Tests validate:
 * - Complete explainability trace generation from all 9 pipeline stages
 * - Stage result aggregation and consolidation
 * - JSON serialization and data integrity
 * - Performance metadata tracking
 * - Configuration reference collection
 * - Database persistence format compatibility
 */

import { generateAuditTrail, AuditTrailResult, PipelineResults, AuditTrailConfig } from '../../src/stages/audit-trail';
import { EmailMessage, ClassificationSession } from '../../src/types';

describe('Audit Trail Generation Stage', () => {
  // Mock email and session data
  const mockEmail: EmailMessage = {
    id: 'email-123',
    from: 'sender@example.com',
    subject: 'Test Email',
    body: 'This is a test email body',
    timestamp: new Date('2025-09-30T10:00:00Z'),
  };

  const mockSession: ClassificationSession = {
    id: 'session-456',
    emailId: 'email-123',
    startedAt: new Date('2025-09-30T10:00:00Z'),
    status: 'completed',
  };

  const mockConfig: AuditTrailConfig = {
    includePerformanceMetrics: true,
    includeConfigurationRefs: true,
    serializationFormat: 'json',
  };

  describe('Complete Explainability Trace Generation', () => {
    it('should aggregate results from all 9 pipeline stages', () => {
      const mockPipelineResults: PipelineResults = {
        hardAssertions: {
          appliedAssertions: [
            {
              category: 'financial',
              assertionType: 'from_domain',
              matchedValue: 'chase.com',
              confidence: 'HIGH_CONFIDENCE',
              triggered: true,
              reason: 'Domain matched hard assertion for financial category',
            },
          ],
          processingDurationMs: 5,
        },
        strongIndicators: {
          appliedIndicators: [
            {
              category: 'financial',
              indicatorType: 'subject_contains',
              matchedValue: 'invoice',
              seedScore: 10,
              diminishingReturnsApplied: false,
              existingSeedScore: 0,
              finalSeedScore: 10,
              reason: 'Subject contains financial keyword',
            },
          ],
          processingDurationMs: 8,
        },
        ruleScoring: {
          categoryScores: { financial: 15.2 },
          subtypeScores: { financial: { invoice: 12, bill_due: 8 } },
          processingDurationMs: 45,
        },
        attributeDetection: {
          detectedAttributes: [
            {
              attribute: 'has_amount',
              detected: true,
