     1→/**
     2→ * Audit Trail Generation Stage
     3→ *
     4→ * Stage 9+ (post-processing) of the EmailCategorizer pipeline. Generates complete
     5→ * explainability traces consolidating results from all 9 classification pipeline stages.
     6→ *
     7→ * This stage is responsible for:
     8→ * - Aggregating results from all pipeline stages into a unified explainability trace
     9→ * - Tracking performance metadata (stage timings, parallel execution maps)
    10→ * - Collecting configuration references used throughout the pipeline
    11→ * - Generating final decision rationale summarizing the complete classification process
    12→ * - Producing database-compatible JSON format for persistence
    13→ *
    14→ * Reference: PrepareRuleScoringPersistenceNode.js and other Prepare*PersistenceNode.js files
    15→ * Document: SCORING_LOGIC.md "Explainability Trace Structure" section
    16→ */
    17→
    18→import { z } from 'zod';
    19→import { EmailMessage, ClassificationSession } from '../types';
    20→import {
    21→  ExplainabilityTrace,
    22→  HardAssertionResult,
    23→  StrongIndicatorResult,
    24→  RuleEvaluationResult,
    25→  AttributeDetectionResult,
    26→  AttributeInfluenceResult,
    27→  DisambiguationResult,
    28→  MultiLabelResult as ExplainMultiLabelResult,
    29→  AIRoutingResult,
    30→} from '../types/explainability-trace';
    31→import { MultiLabelSelectionResult } from './types';
    32→import { FinalDecisionResult } from './final-decision';
    33→
    34→// Zod schema for audit trail configuration
    35→export const AuditTrailConfigSchema = z.object({
    36→  includePerformanceMetrics: z.boolean().default(true),
    37→  includeConfigurationRefs: z.boolean().default(true),
    38→  serializationFormat: z.enum(['json', 'jsonb']).default('json'),
    39→});
    40→
    41→// Configuration interface for audit trail generation
    42→export interface AuditTrailConfig {
    43→  includePerformanceMetrics: boolean;
    44→  includeConfigurationRefs: boolean;
    45→  serializationFormat: 'json' | 'jsonb';
    46→}
    47→
    48→// Pipeline results interface aggregating all stage outputs
    49→export interface PipelineResults {
    50→  hardAssertions: HardAssertionsStageResult;
    51→  strongIndicators: StrongIndicatorsStageResult;
    52→  ruleScoring: RuleScoringStageResult;
    53→  attributeDetection: AttributeDetectionStageResult;
    54→  attributeInfluence: AttributeInfluenceStageResult;
    55→  disambiguation: DisambiguationStageResult;
    56→  multiLabelSelection: MultiLabelSelectionResult;
    57→  aiRouting: AIRoutingStageResult;
    58→  finalDecision: FinalDecisionResult;
    59→}
    60→
    61→// Individual stage result interfaces
    62→export interface HardAssertionsStageResult {
    63→  appliedAssertions: HardAssertionResult[];
    64→  processingDurationMs: number;
    65→}
    66→
    67→export interface StrongIndicatorsStageResult {
    68→  appliedIndicators: StrongIndicatorResult[];
    69→  processingDurationMs: number;
    70→}
    71→
    72→export interface RuleScoringStageResult {
    73→  categoryScores: Record<string, number>;
    74→  subtypeScores: Record<string, Record<string, number>>;
    75→  ruleMatches?: RuleEvaluationResult[];
    76→  processingDurationMs: number;
    77→}
    78→
    79→export interface AttributeDetectionStageResult {
    80→  detectedAttributes: AttributeDetectionResult[];
    81→  processingDurationMs: number;
    82→}
    83→
    84→export interface AttributeInfluenceStageResult {
    85→  appliedInfluences: AttributeInfluenceResult[];
    86→  processingDurationMs: number;
    87→}
    88→
    89→export interface DisambiguationStageResult {
    90→  adjustments: DisambiguationResult[];
    91→  processingDurationMs: number;
    92→}
    93→
    94→export interface AIRoutingStageResult {
    95→  routingDecision: 'skip_ai' | 'feature_extraction' | 'full_classification';
    96→  highConfidenceThreshold: number;
    97→  aiRequiredThreshold: number;
    98→  skipConditions: string[];
    99→  aiResponse?: {
   100→    extractedFeatures?: object;
   101→    suggestedCategories?: string[];
   102→    confidence: number;
   103→    reasoning: string;
   104→  };
   105→  reason: string;
   106→  processingDurationMs: number;
   107→}
   108→
   109→// Complete audit trail result
   110→export interface AuditTrailResult {
   111→  sessionId: string;
   112→  emailId: string;
   113→  explainabilityTrace: ExplainabilityTrace;
   114→  processingDurationMs: number;
   115→}
   116→
   117→/**
   118→ * Generate Audit Trail
   119→ *
   120→ * Consolidates results from all 9 pipeline stages into a complete explainability trace
   121→ * for database persistence and debugging purposes.
   122→ *
   123→ * @param email - Email message being classified
   124→ * @param session - Classification session metadata
   125→ * @param pipelineResults - Results from all 9 pipeline stages
   126→ * @param config - Audit trail configuration
   127→ * @returns Complete audit trail with explainability trace
   128→ */
   129→export function generateAuditTrail(
   130→  email: EmailMessage,
   131→  session: ClassificationSession,
   132→  pipelineResults: PipelineResults,
   133→  config: AuditTrailConfig
   134→): AuditTrailResult {
   135→  const startTime = Date.now();
   136→
   137→  // Validate inputs
   138→  validateInputs(email, session, pipelineResults);
   139→
   140→  // Extract session and email IDs (support both id and legacy _id formats)
   141→  const sessionId = session.id || ((session as unknown as Record<string, unknown>).session_id as string);
   142→  const emailId = email.id || ((email as unknown as Record<string, unknown>).gmail_id as string);
   143→
   144→  // Aggregate stage timings
   145→  const stageTimings = aggregateStageTimings(pipelineResults);
   146→
   147→  // Build parallel execution map
   148→  const parallelExecutionMap = buildParallelExecutionMap(pipelineResults);
   149→
   150→  // Collect configuration references
   151→  const configurationRefs = config.includeConfigurationRefs ? collectConfigurationReferences(pipelineResults) : {};
   152→
   153→  // Generate final decision reason
   154→  const finalDecisionReason = generateFinalDecisionReason(pipelineResults);
   155→
   156→  // Extract alternative categories
   157→  const alternativeCategories = extractAlternativeCategories(pipelineResults);
   158→
   159→  // Convert multi-label selection results to explainability format
   160→  const multiLabelResults = convertMultiLabelResults(pipelineResults.multiLabelSelection);
   161→
   162→  // Build AI routing result
   163→  const aiRoutingResult = buildAIRoutingResult(pipelineResults.aiRouting);
   164→
   165→  // Construct complete explainability trace
   166→  const explainabilityTrace: ExplainabilityTrace = {
   167→    sessionId,
   168→    emailId,
   169→    hardAssertions: pipelineResults.hardAssertions.appliedAssertions,
   170→    strongIndicators: pipelineResults.strongIndicators.appliedIndicators,
   171→    ruleScoring: pipelineResults.ruleScoring.ruleMatches || [],
   172→    attributeDetection: pipelineResults.attributeDetection.detectedAttributes,
   173→    attributeInfluence: pipelineResults.attributeInfluence.appliedInfluences,
   174→    disambiguation: pipelineResults.disambiguation.adjustments,
   175→    multiLabelSelection: multiLabelResults,
   176→    aiRouting: aiRoutingResult,
   177→    stageTimings,
   178→    parallelExecutionMap,
   179→    configurationRefs,
   180→    finalDecisionReason,
   181→    alternativeCategories,
   182→  };
   183→
   184→  return {
   185→    sessionId,
   186→    emailId,
   187→    explainabilityTrace,
   188→    processingDurationMs: Date.now() - startTime,
   189→  };
   190→}
   191→
   192→/**
   193→ * Validate input parameters
   194→ */
   195→function validateInputs(email: EmailMessage, session: ClassificationSession, pipelineResults: PipelineResults): void {
   196→  if (!email || (!email.id && !(email as unknown as Record<string, unknown>).gmail_id)) {
   197→    throw new Error('Invalid email input: id or gmail_id is required');
   198→  }
   199→
   200→  if (!session || (!session.id && !(session as unknown as Record<string, unknown>).session_id)) {
   201→    throw new Error('Invalid session input: id or session_id is required');
   202→  }
   203→
   204→  if (!pipelineResults || typeof pipelineResults !== 'object') {
   205→    throw new Error('Invalid pipeline results: object required');
   206→  }
   207→
   208→  // Validate required stages
   209→  const requiredStages = [
   210→    'hardAssertions',
   211→    'strongIndicators',
   212→    'ruleScoring',
   213→    'attributeDetection',
   214→    'attributeInfluence',
   215→    'disambiguation',
   216→    'multiLabelSelection',
   217→    'aiRouting',
   218→    'finalDecision',
   219→  ];
   220→
   221→  for (const stage of requiredStages) {
   222→    if (!pipelineResults[stage as keyof PipelineResults]) {
   223→      throw new Error(`Missing required pipeline stage: ${stage}`);
   224→    }
   225→  }
   226→}
   227→
   228→/**
   229→ * Aggregate stage timings from all pipeline stages
   230→ */
   231→function aggregateStageTimings(pipelineResults: PipelineResults): Record<string, number> {
   232→  return {
   233→    hardAssertions: pipelineResults.hardAssertions.processingDurationMs,
   234→    strongIndicators: pipelineResults.strongIndicators.processingDurationMs,
   235→    ruleScoring: pipelineResults.ruleScoring.processingDurationMs,
   236→    attributeDetection: pipelineResults.attributeDetection.processingDurationMs,
   237→    attributeInfluence: pipelineResults.attributeInfluence.processingDurationMs,
   238→    disambiguation: pipelineResults.disambiguation.processingDurationMs,
   239→    multiLabelSelection: pipelineResults.multiLabelSelection.processingDurationMs,
   240→    aiRouting: pipelineResults.aiRouting.processingDurationMs,
   241→    finalDecision: pipelineResults.finalDecision.processingDurationMs,
   242→  };
   243→}
   244→
   245→/**
   246→ * Build parallel execution map tracking which stages/attributes ran concurrently
   247→ */
   248→function buildParallelExecutionMap(pipelineResults: PipelineResults): Record<string, string[]> {
   249→  const parallelMap: Record<string, string[]> = {};
   250→
   251→  // Track parallel-processed attributes from attribute detection stage
   252→  const parallelAttributes = pipelineResults.attributeDetection.detectedAttributes
   253→    .filter((attr) => attr.parallelProcessed)
   254→    .map((attr) => attr.attribute);
   255→
   256→  if (parallelAttributes.length > 0) {
   257→    parallelMap.attributeDetection = parallelAttributes;
   258→  }
   259→
   260→  return parallelMap;
   261→}
   262→
   263→/**
   264→ * Collect configuration references used throughout the pipeline
   265→ */
   266→function collectConfigurationReferences(pipelineResults: PipelineResults): Record<string, string> {
   267→  const refs: Record<string, string> = {};
   268→
   269→  // Hard assertions config
   270→  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
   271→    refs.hardAssertions = 'config.processing_config.category_signals.*.hard_assertions';
   272→  }
   273→
   274→  // Strong indicators config
   275→  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
   276→    refs.strongIndicators = 'config.processing_config.category_signals.*.strong_indicators';
   277→  }
   278→
   279→  // Rule scoring config
   280→  if (Object.keys(pipelineResults.ruleScoring.categoryScores).length > 0) {
   281→    refs.ruleScoring = 'config.processing_config.top_level_categories.*.subtypes.*.rule_based_classification';
   282→  }
   283→
   284→  // Attribute detection config
   285→  if (pipelineResults.attributeDetection.detectedAttributes.length > 0) {
   286→    refs.attributeDetection = 'config.processing_config.attributes.detectors';
   287→  }
   288→
   289→  // Attribute influence config
   290→  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
   291→    refs.attributeInfluence = 'config.processing_config.attribute_relevance';
   292→  }
   293→
   294→  // Disambiguation config
   295→  if (pipelineResults.disambiguation.adjustments.length > 0) {
   296→    refs.disambiguation = 'config.processing_config.settings.disambiguation.confidence_gap_threshold';
   297→  }
   298→
   299→  // Multi-label selection config
   300→  refs.multiLabelSelection = 'config.processing_config.multi_label_policy';
   301→
   302→  // AI routing config
   303→  refs.aiRouting = 'config.processing_config.confidence_thresholds';
   304→
   305→  // Final decision config
   306→  refs.finalDecision = 'config.processing_config.settings.archive_threshold';
   307→
   308→  return refs;
   309→}
   310→
   311→/**
   312→ * Generate final decision reason summarizing the complete classification pipeline
   313→ */
   314→function generateFinalDecisionReason(pipelineResults: PipelineResults): string {
   315→  const reasons: string[] = [];
   316→
   317→  // Check for hard assertions (highest priority)
   318→  if (pipelineResults.hardAssertions.appliedAssertions.length > 0) {
   319→    const categories = pipelineResults.hardAssertions.appliedAssertions.map((a) => a.category);
   320→    reasons.push(`Hard assertion matched for categories: ${[...new Set(categories)].join(', ')}`);
   321→  }
   322→
   323→  // Check for strong indicators
   324→  if (pipelineResults.strongIndicators.appliedIndicators.length > 0) {
   325→    const categories = pipelineResults.strongIndicators.appliedIndicators.map((i) => i.category);
   326→    reasons.push(`Strong indicators detected for: ${[...new Set(categories)].join(', ')}`);
   327→  }
   328→
   329→  // Include rule scoring results
   330→  const topCategories = Object.entries(pipelineResults.ruleScoring.categoryScores)
   331→    .sort((a, b) => b[1] - a[1])
   332→    .slice(0, 3);
   333→
   334→  if (topCategories.length > 0) {
   335→    const categoryScores = topCategories.map(([cat, score]) => `${cat}:${score.toFixed(1)}`).join(', ');
   336→    reasons.push(`Top rule-based scores: ${categoryScores}`);
   337→  }
   338→
   339→  // Include attribute influences
   340→  if (pipelineResults.attributeInfluence.appliedInfluences.length > 0) {
   341→    const attributeCount = pipelineResults.attributeInfluence.appliedInfluences.length;
   342→    reasons.push(`${attributeCount} attribute bonuses applied`);
   343→  }
   344→
   345→  // Include AI routing decision
   346→  if (pipelineResults.aiRouting.routingDecision !== 'skip_ai') {
   347→    reasons.push(`AI classification used: ${pipelineResults.aiRouting.reason}`);
   348→  }
   349→
   350→  // Include final decision
   351→  const finalLabels = pipelineResults.finalDecision.assignedLabels;
   352→  reasons.push(`Final assignment: primary=${finalLabels.primary}, secondary=[${finalLabels.secondary.join(', ')}]`);
   353→
   354→  if (pipelineResults.finalDecision.determinedActions.length > 0) {
   355→    reasons.push(`Actions: ${pipelineResults.finalDecision.determinedActions.join(', ')}`);
   356→  }
   357→
   358→  return reasons.join('; ');
   359→}
   360→
   361→/**
   362→ * Extract alternative categories that were not selected
   363→ */
   364→function extractAlternativeCategories(pipelineResults: PipelineResults): Array<{
   365→  category: string;
   366→  score: number;
   367→  eliminationReason: string;
   368→}> {
   369→  const alternatives: Array<{
   370→    category: string;
   371→    score: number;
   372→    eliminationReason: string;
   373→  }> = [];
   374→
   375→  const finalPrimary = pipelineResults.finalDecision.assignedLabels.primary;
   376→  const finalSecondary = pipelineResults.finalDecision.assignedLabels.secondary;
   377→  const selectedCategories = [finalPrimary, ...finalSecondary];
   378→
   379→  // Get all categories from rule scoring
   380→  const allCategories = Object.entries(pipelineResults.ruleScoring.categoryScores);
   381→
   382→  for (const [category, score] of allCategories) {
   383→    if (!selectedCategories.includes(category)) {
   384→      let eliminationReason = 'Score below selection threshold';
   385→
   386→      // Check if filtered by multi-label selection
   387→      const filteredLabels = pipelineResults.finalDecision.explainabilityTrace.filteredLabels || [];
   388→      const wasFiltered = filteredLabels.find((f) => f.category === category);
   389→      if (wasFiltered) {
   390→        eliminationReason = wasFiltered.filterReason;
   391→      }
   392→
   393→      alternatives.push({
   394→        category,
   395→        score,
   396→        eliminationReason,
   397→      });
   398→    }
   399→  }
   400→
   401→  // Sort by score descending
   402→  alternatives.sort((a, b) => b.score - a.score);
   403→
   404→  return alternatives;
   405→}
   406→
   407→/**
   408→ * Convert multi-label selection results to explainability format
   409→ */
   410→function convertMultiLabelResults(multiLabelResult: MultiLabelSelectionResult): ExplainMultiLabelResult[] {
   411→  return multiLabelResult.selectedLabels.map((label) => ({
   412→    selectedCategories: [label.category],
   413→    rejectedCategories: [],
   414→    coPresenceRulesApplied: [],
   415→    maxLabelsLimit: 1,
   416→    minSecondaryConfidence: 0,
   417→    reason: label.selectionRationale,
   418→  }));
   419→}
   420→
   421→/**
   422→ * Build AI routing result for explainability trace
   423→ */
   424→function buildAIRoutingResult(aiRoutingResult: AIRoutingStageResult): AIRoutingResult | undefined {
   425→  // AI routing is optional - only include if AI was actually used
   426→  if (aiRoutingResult.routingDecision === 'skip_ai' && !aiRoutingResult.aiResponse) {
   427→    return {
   428→      routingDecision: aiRoutingResult.routingDecision,
   429→      highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
   430→      aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
   431→      skipConditions: aiRoutingResult.skipConditions,
   432→      reason: aiRoutingResult.reason,
   433→    };
   434→  }
   435→
   436→  return {
   437→    routingDecision: aiRoutingResult.routingDecision,
   438→    highConfidenceThreshold: aiRoutingResult.highConfidenceThreshold,
   439→    aiRequiredThreshold: aiRoutingResult.aiRequiredThreshold,
   440→    skipConditions: aiRoutingResult.skipConditions,
   441→    aiResponse: aiRoutingResult.aiResponse,
   442→    reason: aiRoutingResult.reason,
   443→  };
   444→}
