              sourceField: 'body',
              confidence: 0.95,
              parallelProcessed: true,
              dependencies: [],
              reason: 'Amount pattern detected in body',
            },
          ],
          processingDurationMs: 20,
        },
        attributeInfluence: {
          appliedInfluences: [
            {
              targetCategory: 'financial',
              attributeUsed: 'has_amount',
              roleType: 'PRIMARY_BOOST',
              bonusAmount: 2,
              scoreBefore: 15.2,
              scoreAfter: 17.2,
              capApplied: false,
              reason: 'Amount attribute boosted financial category',
            },
          ],
          processingDurationMs: 12,
        },
        disambiguation: {
          adjustments: [],
          processingDurationMs: 5,
        },
        multiLabelSelection: {
          selectedLabels: [
            {
              category: 'financial',
              subtype: 'invoice',
              confidence: 0.92,
              score: 17.2,
              isPrimary: true,
              labelOrder: 1,
              selectionRationale: 'Highest scoring category with hard assertion',
            },
          ],
          needsAiClassification: false,
          selectionSummary: {
            totalLabels: 1,
            primaryCategory: 'financial',
            confidenceRange: [0.92, 0.92],
            selectionMethod: 'single_label',
            needsAi: false,
          },
          processingDurationMs: 15,
        },
        aiRouting: {
          routingDecision: 'skip_ai',
          highConfidenceThreshold: 15,
          aiRequiredThreshold: 3,
          skipConditions: ['high_confidence_score', 'hard_assertion_present'],
          reason: 'High confidence classification, AI not needed',
          processingDurationMs: 3,
        },
        finalDecision: {
          assignedLabels: {
            primary: 'financial',
            secondary: [],
          },
          determinedActions: ['mark_as_read'],
          actionReasoning: 'Financial emails are marked as read automatically',
          processingDurationMs: 10,
          validationErrors: [],
          explainabilityTrace: {
            aiClassificationInput: {
              primary_category: 'financial',
              secondary_categories: [],
              confidence: 0.92,
              reasoning: 'High confidence direct classification',
              category_scores: { financial: 17.2 },
            },
            labelAssignmentRationale: 'Primary category assigned based on highest score',
            actionDeterminationRationale: 'Applied category-specific actions',
            processingSteps: ['Input validation completed', 'Labels assigned', 'Actions determined'],
          },
        },
      };

      const result = generateAuditTrail(mockEmail, mockSession, mockPipelineResults, mockConfig);

      // Validate trace includes all 9 stages
      expect(result.explainabilityTrace).toBeDefined();
      expect(result.explainabilityTrace.hardAssertions).toHaveLength(1);
      expect(result.explainabilityTrace.strongIndicators).toHaveLength(1);
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(result.explainabilityTrace.attributeDetection).toHaveLength(1);
      expect(result.explainabilityTrace.attributeInfluence).toHaveLength(1);
      expect(result.explainabilityTrace.disambiguation).toEqual([]);
      expect(result.explainabilityTrace.multiLabelSelection).toHaveLength(1);
      expect(result.explainabilityTrace.aiRouting).toBeDefined();
      expect(result.explainabilityTrace.finalDecisionReason).toBeDefined();
    });

    it('should include performance metadata from all stages', () => {
      const mockPipelineResults: PipelineResults = {
        hardAssertions: { appliedAssertions: [], processingDurationMs: 5 },
        strongIndicators: { appliedIndicators: [], processingDurationMs: 8 },
        ruleScoring: { categoryScores: {}, subtypeScores: {}, processingDurationMs: 45 },
        attributeDetection: { detectedAttributes: [], processingDurationMs: 20 },
        attributeInfluence: { appliedInfluences: [], processingDurationMs: 12 },
        disambiguation: { adjustments: [], processingDurationMs: 5 },
        multiLabelSelection: {
          selectedLabels: [],
          needsAiClassification: true,
          selectionSummary: {
            totalLabels: 0,
            primaryCategory: null,
            confidenceRange: [0, 0],
            selectionMethod: 'none_selected',
            needsAi: true,
          },
          processingDurationMs: 15,
        },
        aiRouting: {
          routingDecision: 'skip_ai',
          highConfidenceThreshold: 15,
          aiRequiredThreshold: 3,
          skipConditions: [],
