            {
              category: 'financial',
              subtype: 'invoice',
              confidence: 0.92,
              score: 17.2,
              isPrimary: true,
              labelOrder: 1,
              selectionRationale: 'Highest scoring category with hard assertion',
            },
          ],
          needsAiClassification: false,
          selectionSummary: {
            totalLabels: 1,
            primaryCategory: 'financial',
            confidenceRange: [0.92, 0.92],
            selectionMethod: 'single_label',
